ylabel(ax, "Probability"); %[output:80ebe080]
%[text] Set ranges on the axes.
%ylim(ax, [0, 0.2]);
xlim(ax, [0, nMax]); %[output:80ebe080]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:80ebe080]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:80ebe080]

% histogram for W_q
fig = figure(); %[output:1b8e0645]
t = tiledlayout(fig,1,1); %[output:1b8e0645]
ax = nexttile(t); %[output:1b8e0645]
TimeWaiting = WaitingInSystemSamples;
h = histogram(ax, TimeWaiting, Normalization = "probability", BinWidth = 5/60); %[output:1b8e0645]
rho = lambda / mu;
tvals = linspace(0, max(TimeWaiting), 300);
%fWq = rho * (mu - lambda) * exp(-(mu - lambda) * tvals);
