xlabel(ax, "Time (hours)"); %[output:1b8e0645]
ylabel(ax, "Probability"); %[output:1b8e0645]
pause(2);
exportgraphics(fig, PictureFolder + filesep + "Wq_histogram.pdf"); %[output:1b8e0645]
ServiceTimes = cellfun(@(q) cellfun(@(c) c.DepartureTime - c.BeginServiceTime, q.Served'), QSamples, UniformOutput=false);
ServiceTimes = vertcat(ServiceTimes{:});
CustomersServed = cellfun(@(q) length(q.Served), QSamples);
%histogram for service times
fig = figure(); %[output:7a05605d]
t = tiledlayout(fig,1,1); %[output:7a05605d]
ax = nexttile(t); %[output:7a05605d]
h = histogram(ax, ServiceTimes, Normalization = "probability", BinWidth = 5/60); %[output:7a05605d]
